body.script:
document.addEventListener("DOMContentLoaded", () => 
{
    window.addEventListener('message', (event) => 
    {
        if (!event.data || typeof event.data !== 'object')
        {
            console.warn("INVALID SIMULATION MESSAGE TYPE")
            return;
        }

        switch (event.data.type) 
        {
            case 'MOUSE_MOVE':
                triggerSplat(event.data.payload.x, event.data.payload.y);
                break;
            case 'MOUSE_DOWN':
                { 
                    pointer.color = generateColor(); 
                    triggerSplat(event.data.payload.x, event.data.payload.y);
                }
                break;
            default:
                console.warn("Received unknown message type:", event.data.type);
        }
    });        

    const canvas = document.getElementById('fluid-sim');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;


    const gl = canvas.getContext('webgl', { alpha: false, antialias: false, depth: false }) || 
               canvas.getContext('experimental-webgl', { alpha: false, antialias: false, depth: false });

    if (!gl) { return alert("WebGL not supported"); }

    // Explicit requests, refuses to render otherwise, still learning webgl so be kind
    gl.getExtension('OES_texture_float');
    gl.getExtension('OES_texture_float_linear');
    gl.getExtension('WEBGL_color_buffer_float');
    const extHalfFloat = gl.getExtension('OES_texture_half_float');
    gl.getExtension('OES_texture_half_float_linear');
    gl.getExtension('EXT_color_buffer_half_float');

    function compileShader(type, source) 
    {
        const shader = gl.createShader(type);
        gl.shaderSource(shader, source);
        gl.compileShader(shader);
        if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) { throw gl.getShaderInfoLog(shader); }
        return shader;
    }

    const baseVertexShader = `
        precision highp float;
        attribute vec2 aPosition;
        varying vec2 vUv;
        void main () 
        {
            vUv = aPosition * 0.5 + 0.5;
            gl_Position = vec4(aPosition, 0.0, 1.0);
        }
    `;

    const advectionShader = `
        precision highp float;
        varying vec2 vUv;
        uniform sampler2D uVelocity;
        uniform sampler2D uSource;
        uniform vec2 texelSize;
        uniform float dt;
        uniform float dissipation;
        void main () {
            vec2 coord = vUv - dt * texture2D(uVelocity, vUv).xy * texelSize;
            gl_FragColor = dissipation * texture2D(uSource, coord);
            gl_FragColor.a = 1.0;
        }
    `;

    const divergenceShader = `
        precision highp float;
        varying vec2 vUv;
        uniform sampler2D uVelocity;
        uniform vec2 texelSize;
        void main () {
            float L = texture2D(uVelocity, vUv - vec2(texelSize.x, 0.0)).x;
            float R = texture2D(uVelocity, vUv + vec2(texelSize.x, 0.0)).x;
            float T = texture2D(uVelocity, vUv + vec2(0.0, texelSize.y)).y;
            float B = texture2D(uVelocity, vUv - vec2(0.0, texelSize.y)).y;
            float div = 0.5 * (R - L + T - B);
            gl_FragColor = vec4(div, 0.0, 0.0, 1.0);
        }
    `;

    const pressureShader = `
        precision highp float;
        varying vec2 vUv;
        uniform sampler2D uPressure;
        uniform sampler2D uDivergence;
        uniform vec2 texelSize;
        void main () {
            float L = texture2D(uPressure, vUv - vec2(texelSize.x, 0.0)).x;
            float R = texture2D(uPressure, vUv + vec2(texelSize.x, 0.0)).x;
            float T = texture2D(uPressure, vUv + vec2(0.0, texelSize.y)).x;
            float B = texture2D(uPressure, vUv - vec2(0.0, texelSize.y)).x;
            float div = texture2D(uDivergence, vUv).x;
            float pressure = (L + R + B + T - div) * 0.25;
            gl_FragColor = vec4(pressure, 0.0, 0.0, 1.0);
        }
    `;

    const gradientSubtractShader = `
        precision highp float;
        varying vec2 vUv;
        uniform sampler2D uPressure;
        uniform sampler2D uVelocity;
        uniform vec2 texelSize;
        void main () {
            float L = texture2D(uPressure, vUv - vec2(texelSize.x, 0.0)).x;
            float R = texture2D(uPressure, vUv + vec2(texelSize.x, 0.0)).x;
            float T = texture2D(uPressure, vUv + vec2(0.0, texelSize.y)).x;
            float B = texture2D(uPressure, vUv - vec2(0.0, texelSize.y)).x;
            vec2 velocity = texture2D(uVelocity, vUv).xy;
            velocity.xy -= vec2(R - L, T - B);
            gl_FragColor = vec4(velocity, 0.0, 1.0);
        }
    `;

    const splatShader = `
        precision highp float;
        varying vec2 vUv;
        uniform sampler2D uTarget;
        uniform float aspectRatio;
        uniform vec3 color;
        uniform vec2 point;
        uniform float radius;
        void main () {
            vec2 p = vUv - point.xy;
            p.x *= aspectRatio;
            vec3 splat = exp(-dot(p, p) / radius) * color;
            vec3 base = texture2D(uTarget, vUv).xyz;
            gl_FragColor = vec4(base + splat, 1.0);
        }
    `;

    const displayShader = `
        precision highp float;
        varying vec2 vUv;
        uniform sampler2D uTexture;
        void main () {
            vec3 c = texture2D(uTexture, vUv).rgb;
            gl_FragColor = vec4(c, 1.0);
        }
    `;

    class Processor 
    {
        constructor(fragmentShaderSource) 
        {
            this.processor = gl.createProgram();
            gl.attachShader(this.processor, compileShader(gl.VERTEX_SHADER, baseVertexShader));
            gl.attachShader(this.processor, compileShader(gl.FRAGMENT_SHADER, fragmentShaderSource));

            // Ensures hardware acceleration and prevents driver-specific crashes by locking the geometry to WebGL's mandatory attribute slot 0.
            gl.bindAttribLocation(this.processor, 0, "aPosition"); 

            gl.linkProgram(this.processor);
            this.uniforms = {};
        }
        bind() { gl.useProgram(this.processor); }
    }

    const processors = 
    {
        advection: new Processor(advectionShader),
        divergence: new Processor(divergenceShader),
        pressure: new Processor(pressureShader),
        gradSubtract: new Processor(gradientSubtractShader),
        splat: new Processor(splatShader),
        display: new Processor(displayShader)
    };

    const floatLinear = gl.getExtension('OES_texture_float_linear');
    const filter = floatLinear ? gl.LINEAR : gl.NEAREST; // Fallback to NEAREST    

    function createFBO(w, h, internalFormat, format, type) 
    {
        gl.activeTexture(gl.TEXTURE0);
        const texture = gl.createTexture();
        gl.bindTexture(gl.TEXTURE_2D, texture);

        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, filter);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, filter);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
        gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
        gl.texImage2D(gl.TEXTURE_2D, 0, internalFormat, w, h, 0, format, type, null);

        const fbo = gl.createFramebuffer();
        gl.bindFramebuffer(gl.FRAMEBUFFER, fbo);
        gl.framebufferTexture2D(gl.FRAMEBUFFER, gl.COLOR_ATTACHMENT0, gl.TEXTURE_2D, texture, 0);

        const isFramebufferIncomplete = gl.checkFramebufferStatus(gl.FRAMEBUFFER) !== gl.FRAMEBUFFER_COMPLETE;
        if (isFramebufferIncomplete) 
        {
            console.error("Framebuffer incomplete");
        }        
        return { texture, fbo, width: w, height: h, texelSizeX: 1.0 / w, texelSizeY: 1.0 / h };
    }

    // Write setter acts as a placeholder to satisfies the JavaScript engine's requirement for a setter. 
    // intentionally ignores the new incoming value (fbo) to protects the internal Framebuffer Object (fbo2) 
    // from being accidentally overwritten or destroyed from outside the function, 
    // ensuring the FBOs are strictly managed by the internal swap() method.
    function createDoubleFBO(w, h, internalFormat, format, type) 
    {
        let fbo1 = createFBO(w, h, internalFormat, format, type);
        let fbo2 = createFBO(w, h, internalFormat, format, type);
        return {
            get read() { return fbo1; },
            set write(fbo) { fbo2 = fbo2; }, // Setter placeholder
            get write() { return fbo2; },
            swap() { let temp = fbo1; fbo1 = fbo2; fbo2 = temp; }
        };
    }

    const simRes = 256; 
    const dyeRes = 1024;
    const type = extHalfFloat ? extHalfFloat.HALF_FLOAT_OES : gl.FLOAT;

    const velocity = createDoubleFBO(simRes, simRes, gl.RGBA, gl.RGBA, type);
    const density  = createDoubleFBO(dyeRes, dyeRes, gl.RGBA, gl.RGBA, type);
    const divergence = createFBO(simRes, simRes, gl.RGBA, gl.RGBA, type);
    const pressure   = createDoubleFBO(simRes, simRes, gl.RGBA, gl.RGBA, type);

    // Geometry setup
    gl.bindBuffer(gl.ARRAY_BUFFER, gl.createBuffer());
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1, -1,1, 1,1, 1,-1]), gl.STATIC_DRAW);
    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, gl.createBuffer());
    gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, new Uint16Array([0,1,2, 0,2,3]), gl.STATIC_DRAW);

    // Globally enable attribute 0
    gl.enableVertexAttribArray(0);
    gl.vertexAttribPointer(0, 2, gl.FLOAT, false, 0, 0);

    function blit(target) 
    {
        if (target == null) 
        {
            gl.viewport(0, 0, gl.drawingBufferWidth, gl.drawingBufferHeight);
            gl.bindFramebuffer(gl.FRAMEBUFFER, null);
        } 
        else 
        {
            gl.viewport(0, 0, target.width, target.height);
            gl.bindFramebuffer(gl.FRAMEBUFFER, target.fbo);
        }
        gl.drawElements(gl.TRIANGLES, 6, gl.UNSIGNED_SHORT, 0);
    }

    let config = 
    { 
        DENSITY_DISSIPATION: 0.97, // Dissipate speed, hopefully will avoid saturating into white
        VELOCITY_DISSIPATION: 0.98, 
        PRESSURE_PASSES: 20, 
        SPLAT_RADIUS: 0.0002,      // Thin lines
        SPLAT_FORCE: 5792.6        // == Large velocity momentum (8192 / 1.4142)
    };

    let pointer = { lastX: 0.5, lastY: 0.5, dx: 0, dy: 0, color: [0,0,0] };

    function generateColor() 
    {
        let c = [Math.random() + 0.1, Math.random() + 0.1, Math.random() + 0.1];
        let max = Math.max(c[0], c[1], c[2]);
        return [c[0]/max, c[1]/max, c[2]/max];
    }

    pointer.color = generateColor();

    let splatStack = [];
    function interpSplats(steps, pointer, advectVx, advectVy, dx, dy)
    {
        for (let interpStep = 0; interpStep < steps; interpStep++) 
            {
                let t = steps === 1 ? 1.0 : interpStep / (steps - 1);
                splatStack.push({
                x: pointer.lastX + dx * t,
                y: pointer.lastY + dy * t,
                dx: advectVx,
                dy: advectVy,
                color: pointer.color
            });
        }
    }
    function triggerSplat(clientX, clientY) 
    {
        let newX = clientX / window.innerWidth;
        let newY = 1.0 - clientY / window.innerHeight;

        let dx = newX - pointer.lastX;
        let dy = newY - pointer.lastY;

        // Calculate velocity for the advection phase
        let advectVx = dx * config.SPLAT_FORCE;
        let advectVy = dy * config.SPLAT_FORCE;
        if (advectVx === 0 && advectVy === 0) { advectVx = 10.0; advectVy = 10.0; }

        let deltaDist = Math.sqrt(dx * dx + dy * dy);

        let steps = Math.max(1, Math.floor(deltaDist / (config.SPLAT_RADIUS * 0.5)));
        steps = Math.min(4, steps);
        interpSplats(steps, pointer, advectVx, advectVy, dx, dy)

        pointer.lastX = newX;
        pointer.lastY = newY;
    }


    window.addEventListener('mousemove', e => triggerSplat(e.clientX, e.clientY));
    window.addEventListener('mousedown', e => { pointer.color = generateColor(); triggerSplat(e.clientX, e.clientY); });
    window.addEventListener('touchstart', e => { pointer.color = generateColor(); triggerSplat(e.touches[0].clientX, e.touches[0].clientY); });
    window.addEventListener('touchmove', e => triggerSplat(e.touches[0].clientX, e.touches[0].clientY));

    function getLoc(processor, name) { return gl.getUniformLocation(processor.processor, name); }

    let lastTime = performance.now();

    const pointerColRefreshTime = 0.95; 
    let lastColRefreshTime = performance.now();
    function step() 
    {
        const now = performance.now();
        const dt = Math.min((now - lastTime) / 1000.0, 0.016);
        lastTime = now;

        const dtRefresh = (now - lastColRefreshTime) / 1000.0;
        if (dtRefresh > pointerColRefreshTime)
        {
            pointer.color = generateColor();
            lastColRefreshTime = now;
        }

        while (splatStack.length > 0) 
        {
            let splat = splatStack.shift();

            processors.splat.bind();
            gl.uniform1i(getLoc(processors.splat, "uTarget"), 0);
            gl.uniform1f(getLoc(processors.splat, "aspectRatio"), canvas.width / canvas.height);

            gl.uniform2f(getLoc(processors.splat, "point"), splat.x, splat.y);
            gl.uniform1f(getLoc(processors.splat, "radius"), config.SPLAT_RADIUS);

            gl.activeTexture(gl.TEXTURE0);
            gl.bindTexture(gl.TEXTURE_2D, velocity.read.texture);
            gl.uniform3f(getLoc(processors.splat, "color"), splat.dx, splat.dy, 0.0);
            blit(velocity.write);
            velocity.swap();

            gl.bindTexture(gl.TEXTURE_2D, density.read.texture);
            gl.uniform3f(getLoc(processors.splat, "color"), splat.color[0], splat.color[1], splat.color[2]);
            blit(density.write);
            density.swap();
        }


        processors.advection.bind();
        gl.uniform2f(getLoc(processors.advection, "texelSize"), velocity.read.texelSizeX, velocity.read.texelSizeY);
        gl.uniform1i(getLoc(processors.advection, "uVelocity"), 0);
        gl.uniform1i(getLoc(processors.advection, "uSource"), 0);
        gl.uniform1f(getLoc(processors.advection, "dt"), dt);
        gl.uniform1f(getLoc(processors.advection, "dissipation"), config.VELOCITY_DISSIPATION);
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, velocity.read.texture);
        blit(velocity.write);
        velocity.swap();

        gl.uniform1i(getLoc(processors.advection, "uVelocity"), 0);
        gl.uniform1i(getLoc(processors.advection, "uSource"), 1);
        gl.uniform1f(getLoc(processors.advection, "dissipation"), config.DENSITY_DISSIPATION);
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, velocity.read.texture);
        gl.activeTexture(gl.TEXTURE1);
        gl.bindTexture(gl.TEXTURE_2D, density.read.texture);
        blit(density.write);
        density.swap();

        processors.divergence.bind();
        gl.uniform2f(getLoc(processors.divergence, "texelSize"), velocity.read.texelSizeX, velocity.read.texelSizeY);
        gl.uniform1i(getLoc(processors.divergence, "uVelocity"), 0);
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, velocity.read.texture);
        blit(divergence);

        gl.bindFramebuffer(gl.FRAMEBUFFER, pressure.read.fbo);
        gl.clearColor(0.42, 0.44, 0.45, 0.3);
        gl.clear(gl.COLOR_BUFFER_BIT);

        processors.pressure.bind();
        gl.uniform2f(getLoc(processors.pressure, "texelSize"), velocity.read.texelSizeX, velocity.read.texelSizeY);
        gl.uniform1i(getLoc(processors.pressure, "uDivergence"), 0);
        gl.uniform1i(getLoc(processors.pressure, "uPressure"), 1);
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, divergence.texture);

        for (let i = 0; i < config.PRESSURE_PASSES; i++) 
        {
            gl.activeTexture(gl.TEXTURE1);
            gl.bindTexture(gl.TEXTURE_2D, pressure.read.texture);
            blit(pressure.write);
            pressure.swap();
        }

        processors.gradSubtract.bind();
        gl.uniform2f(getLoc(processors.gradSubtract, "texelSize"), velocity.read.texelSizeX, velocity.read.texelSizeY);
        gl.uniform1i(getLoc(processors.gradSubtract, "uPressure"), 0);
        gl.uniform1i(getLoc(processors.gradSubtract, "uVelocity"), 1);
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, pressure.read.texture);
        gl.activeTexture(gl.TEXTURE1);
        gl.bindTexture(gl.TEXTURE_2D, velocity.read.texture);
        blit(velocity.write);
        velocity.swap();

        processors.display.bind();
        gl.uniform1i(getLoc(processors.display, "uTexture"), 0);
        gl.activeTexture(gl.TEXTURE0);
        gl.bindTexture(gl.TEXTURE_2D, density.read.texture);
        blit(null); 

        requestAnimationFrame(step);
    }

    step();
});
